// --- NAPRAWIONY AKORDEON (DZIAŁAJĄCY W 100%) ---
function AccordionSection({ id, title, paragraphs }) {
  const [isOpen, setIsOpen] = useState(false);
  const contentRef = useRef(null);
  const [height, setHeight] = useState(0);

  // Obliczamy wysokość po otwarciu
  useEffect(() => {
    if (isOpen && contentRef.current) {
      setHeight(contentRef.current.scrollHeight);
    } else {
      setHeight(0);
    }
  }, [isOpen]);

  return (
    <section id={id} style={{ paddingTop: "10px", paddingBottom: "10px" }}>
      <div
        style={{
          background: isOpen ? "#fff" : "#E0F0FF",
          padding: "26px",
          borderRadius: "18px",
          boxShadow: isOpen
            ? "0 8px 30px rgba(0, 113, 227, 0.15)"
            : "0 4px 15px rgba(0,0,0,0.05)",
          cursor: "pointer",
          transition: "background 0.3s, box-shadow 0.3s"
        }}
        onClick={() => setIsOpen(!isOpen)}
      >
        {/* Nagłówek */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center"
          }}
        >
          <h2
            style={{
              fontSize: "clamp(1rem, 3.5vw, 1.25rem)",
              fontWeight: 700,
              margin: 0,
              paddingRight: "15px"
            }}
          >
            {title}
          </h2>
          <div
            style={{
              transition: "transform 0.3s",
              transform: isOpen ? "rotate(180deg)" : "rotate(0deg)",
              color: "#0071E3"
            }}
          >
            {isOpen ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
          </div>
        </div>

        {/* TREŚĆ – teraz ZAWSZE renderowana, błędy znikają */}
        <div
          style={{
            overflow: "hidden",
            height,
            transition: "height 0.3s ease-in-out"
          }}
        >
          <div
            ref={contentRef}
            style={{
              paddingTop: isOpen ? "15px" : "0",
              opacity: isOpen ? 1 : 0,
              transition: "opacity 0.3s ease-in-out",
              display: "flex",
              flexDirection: "column",
              gap: "12px"
            }}
          >
            {paragraphs.map((p, i) => (
              <p key={i} style={{ margin: 0, lineHeight: 1.65 }}>
                {p}
              </p>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

